var src = inputs[0];
var rotX = GetFloat(parameters, "rotationX", 15f);
var rotY = GetFloat(parameters, "rotationY", 10f);
var scale = Math.Max(0.1f, GetFloat(parameters, "scale", 1.0f));
var size = context.TileSize;
var result = new PixelBuffer(size, size);
if (src == null) return result;
var cx = size * 0.5f; var cy = size * 0.5f;
var rxRad = rotX * MathF.PI / 180f;
var ryRad = rotY * MathF.PI / 180f;
result.ParallelForEachPixel((x, y) =>
{
    var nx = (x - cx) / (size * scale);
    var ny = (y - cy) / (size * scale);
    // Rotation X: compress rows at top/bottom
    var cosX = MathF.Cos(rxRad * ny);
    var sx2 = nx / Math.Max(0.01f, cosX);
    // Rotation Y: skew columns based on row
    var sx3 = sx2 - ny * MathF.Sin(ryRad);
    var srcX = (int)((sx3 + 0.5f) * size);
    var srcY = (int)((ny + 0.5f) * size);
    if (srcX < 0 || srcX >= size || srcY < 0 || srcY >= size)
    {
        result.SetPixel(x, y, 0, 0, 0, 0);
    }
    else
    {
        var (r, g, b, a) = src.GetPixel(srcX, srcY);
        result.SetPixel(x, y, r, g, b, a);
    }
});
return result;
}
